export const getGetSpendingByCategoryUrl = (params?: GetSpendingByCategoryParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/summary/spending-by-category?${stringifiedParams}` : `/api/summary/spending-by-category`
}

